-- DevOps Engineer Roadmap seed.
-- Idempotent seed. Safe to rerun.
BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;

DROP TABLE IF EXISTS seed_edge;
DROP TABLE IF EXISTS seed_node_resource;
DROP TABLE IF EXISTS seed_node_skill;
DROP TABLE IF EXISTS seed_node;
DROP TABLE IF EXISTS seed_resource;
DROP TABLE IF EXISTS seed_skill;
DROP TABLE IF EXISTS seed_roadmap_map;

-- Clean previous copy of this specific roadmap only.
DELETE FROM public.progress_event
WHERE roadmap_enrollment_id IN (
    SELECT e.roadmap_enrollment_id
    FROM public.roadmap_enrollment e
    JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title IN ('DevOps Engineer Roadmap', 'DevOps Roadmap', 'DevOps Engineer Roadmap - Full Detailed Seed')
);

DELETE FROM public.user_node_progress
WHERE roadmap_enrollment_id IN (
    SELECT e.roadmap_enrollment_id
    FROM public.roadmap_enrollment e
    JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title IN ('DevOps Engineer Roadmap', 'DevOps Roadmap', 'DevOps Engineer Roadmap - Full Detailed Seed')
);

DELETE FROM public.roadmap_enrollment
WHERE roadmap_version_id IN (
    SELECT rv.roadmap_version_id
    FROM public.roadmap_version rv
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title IN ('DevOps Engineer Roadmap', 'DevOps Roadmap', 'DevOps Engineer Roadmap - Full Detailed Seed')
);

DELETE FROM public.roadmap
WHERE title IN ('DevOps Engineer Roadmap', 'DevOps Roadmap', 'DevOps Engineer Roadmap - Full Detailed Seed');

VALUES (
    'DevOps Engineer',
    'devops-engineer',
    'DevOps engineering path covering Linux, networking, automation, CI/CD, containers, Kubernetes, cloud, infrastructure as code, observability, security, reliability, and platform engineering.',
    'Cloud and Infrastructure',
    true
)
ON CONFLICT (slug) DO UPDATE SET
    name = EXCLUDED.name,
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    is_active = true,
    updated_at = now();

DROP TABLE IF EXISTS seed_roadmap_map;
CREATE TEMP TABLE seed_roadmap_map AS
WITH role_row AS (
    SELECT career_role_id FROM public.career_role WHERE slug = 'devops-engineer'
), inserted_roadmap AS (
SELECT career_role_id, 'DevOps Engineer Roadmap', 'A structured learning path for becoming a DevOps engineer, covering Linux, networking, scripting, Git, CI/CD, containers, Kubernetes, cloud infrastructure, infrastructure as code, observability, security, reliability, platform engineering, and production-ready deployment workflows.', 'public'
FROM role_row
    RETURNING roadmap_id
), inserted_version AS (
SELECT
    roadmap_id,
    1,
    1,
    0,
    0,
    'initial',
    'published',
    'DevOps Engineer Roadmap',
    'A practical DevOps engineering roadmap that moves from systems and delivery foundations to production-ready infrastructure, automation, reliability, security, and platform engineering work.',
    410,
    'TB',
    'custom',
    now()
FROM inserted_roadmap
    RETURNING roadmap_version_id, roadmap_id
)
SELECT roadmap_id, roadmap_version_id FROM inserted_version;

