DROP TABLE IF EXISTS seed_skill;
CREATE TEMP TABLE seed_skill (
    slug text PRIMARY KEY,
    name text NOT NULL,
    category text NOT NULL,
    description text NOT NULL
) ON COMMIT DROP;





